</main><script>fetch('{{ url('/api/countries/'.$countryData->id.'/analytics') }}').then(r=>r.json()).then(({data})=>{const g=data.economics['NY.GDP.MKTP.CD']||[],i=data.economics['FP.CPI.TOTL.ZG']||[];const years=[...new Set([...g,...i].map(x=>x.recorded_year))].sort();new Chart(document.getElementById('economicChart'),{type:'line',data:{labels:years,datasets:[{label:'GDP (miliar USD)',data:years.map(y=>(g.find(x=>x.recorded_year==y)?.indicator_value||null)/1e9),borderColor:'#2563eb',yAxisID:'y'},{label:'Inflasi (%)',data:years.map(y=>i.find(x=>x.recorded_year==y)?.indicator_value||null),borderColor:'#dc2626',yAxisID:'y1'}]},options:{responsive:true,maintainAspectRatio:false,scales:{y1:{position:'right',grid:{drawOnChartArea:false}}}}});const risk=data.risk||[];new Chart(document.getElementById('riskTrendChart'),{type:'line',data:{labels:risk.map(x=>new Date(x.created_at).toLocaleDateString('id-ID')),datasets:[{label:'Total Risk',data:risk.map(x=>x.total_risk_score),borderColor:'#7c3aed',backgroundColor:'#7c3aed22',fill:true,tension:.3}]},options:{responsive:true,maintainAspectRatio:false,scales:{y:{min:0,max:100}}}})});</script></body></html>
